module RefModule 
(
  input rst,
  input clk,

  output reg [5:0] count
);

  reg [5:0] obf_binary_count;

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      obf_binary_count <= 6'b000000;
      count <= 6'b000000;
    end 
	else 
	begin
      obf_binary_count <= obf_binary_count + 1;
      count <= (obf_binary_count >> 1) ^ obf_binary_count;
    end
  end

endmodule
